parameters.functionCode:
// 解析 EasyStore order webhook payload
const payload = $json;

const order_id = payload.id || '';
const event_type = payload.topic || 'orders/create';
const order_number = payload.order_number || payload.name || '';

// Customer info
const customer = payload.customer || {};
const customer_email = customer.email || '';
const customer_name = (customer.first_name || '') + ' ' + (customer.last_name || '');
const customer_phone = customer.phone || '';

// Order details
const total_price = parseFloat(payload.total_price) || 0;
const currency = payload.currency || 'TWD';
const financial_status = payload.financial_status || 'pending';
const fulfillment_status = payload.fulfillment_status || '';

// Line items summary
const line_items = payload.line_items || [];
const items_summary = line_items.map(item => 
  `${item.title || item.name} x${item.quantity}`
).join(', ');

// Try to find line_user_id from note or UTM
const note = payload.note || '';
const line_user_id_match = note.match(/line_user_id[=:]([^&\s]+)/);
const line_user_id = line_user_id_match ? line_user_id_match[1] : '';

return [{
  json: {
    order_id: String(order_id),
    event_type,
    order_number,
    customer_email,
    customer_name: customer_name.trim(),
    customer_phone,
    total_price,
    currency,
    financial_status,
    fulfillment_status,
    items_summary,
    line_user_id,
    raw_payload: JSON.stringify(payload)
  }
}];

